#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
//#define int long long
using namespace std;
const int N=1e6+10,Mod=104857601,INF=0x3f3f3f3f;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
bool vis[N];int mu[N],cnt,pm[78505];
inline void Init(int mx)
{
	vis[1]=1;mu[1]=1;rep(2,mx,i)
	{
		if(!vis[i])mu[pm[++cnt]=i]=-1;
		rep(1,cnt,j)
		{
			if(pm[j]*i>mx)break;
			mu[pm[j]*i]=(i%pm[j]==0)?0:-mu[i];
			vis[pm[j]*i]=1;if(i%pm[j]==0)break;
		}
	}
	rep(1,mx,i)mu[i]+=mu[i-1];
}
inline int qpow(int x,long long k)
	{int res=1;while(k){if(k&1)res=1ll*res*x%Mod;x=1ll*x*x%Mod;k=k>>1;}return res;}
inline long long Cnt(int n)
{
	long long res=0;for(int l=1,r=0;l<=n;l=r+1)
		{r=n/(n/l);res+=1ll*(n/l)*(n/l)*(mu[r]-mu[l-1]);}return res;
}
int main()
{
	int n=read();Init(n);long long ans=1;
	long long las=INF,lv;rep(1,n,i)
	{
		int tmp=n/i;if(tmp==las)ans=ans*qpow(i,lv)%Mod;
		else las=tmp,ans=ans*qpow(i,lv=Cnt(tmp))%Mod;
	}ans=qpow(ans,Mod-2);ans=ans*ans%Mod;
	int tmp=1;rep(2,n,i)tmp=1ll*tmp*i%Mod;tmp=qpow(tmp,n<<1);
	ans=ans*tmp%Mod;printf("%lld\n",ans%Mod);
}
